import pyotp
import qrcode
import base64
import time

class TOTPAuthenticator:
    def __init__(self, issuer_name="MyCompanyMFA"):
        self.issuer_name = issuer_name

    def generate_secret(self):
        """Generates a new base32-encoded random secret."""
        return pyotp.random_base32()

    def get_provisioning_uri(self, secret, account_name):
        """
        Generates the provisioning URI for a given secret and account name.
        This URI can be used to generate a QR code.
        """
        return pyotp.totp.TOTP(secret).provisioning_uri(
            name=account_name,
            issuer_name=self.issuer_name
        )

    def generate_qr_code_data(self, secret, account_name):
        """
        Generates the base64 encoded PNG data for a QR code.
        This QR code can be scanned by authenticator apps like Google Authenticator.
        """
        provisioning_uri = self.get_provisioning_uri(secret, account_name)
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(provisioning_uri)
        qr.make(fit=True)
        img = qr.make_image(fill_color="black", back_color="white")

        import io
        buffered = io.BytesIO()
        img.save(buffered, format="PNG")
        return base64.b64encode(buffered.getvalue()).decode("utf-8")

    def verify_totp(self, secret, user_totp_code):
        """
        Verifies a user-provided TOTP code against the secret.
        Allows for a small time drift (default 1 time step, 30 seconds).
        """
        totp = pyotp.TOTP(secret)
        return totp.verify(user_totp_code)

    def get_current_totp(self, secret):
        """
        Returns the current valid TOTP code for a given secret.
        Useful for testing or displaying the expected code.
        """
        totp = pyotp.TOTP(secret)
        return totp.now()

